import { useState, useEffect } from "react";
import problemsData from "../data/problems.json";
import Navbar from "../components/Navbar";
import Sidebar from "../components/Sidebar";
import ProblemCard from "../components/ProblemCard";
import FilterBar from "../components/FilterBar";
import ProgressBar from "../components/ProgressBar";

function Sheet() {
  const [problems, setProblems] = useState([]);
  const [selectedTopic, setSelectedTopic] = useState("All");
  const [difficulty, setDifficulty] = useState("All");
  const [search, setSearch] = useState("");

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("dsaProgress")) || {};
    const updated = problemsData.map((p) => ({
      ...p,
      solved: saved[p.id] || false,
    }));
    setProblems(updated);
  }, []);

  useEffect(() => {
    const progress = {};
    problems.forEach((p) => {
      progress[p.id] = p.solved;
    });
    localStorage.setItem("dsaProgress", JSON.stringify(progress));
  }, [problems]);

  const toggleSolved = (id) => {
    setProblems((prev) =>
      prev.map((p) =>
        p.id === id ? { ...p, solved: !p.solved } : p
      )
    );
  };

  const filtered = problems.filter((p) => {
    return (
      (selectedTopic === "All" || p.topic === selectedTopic) &&
      (difficulty === "All" || p.difficulty === difficulty) &&
      p.title.toLowerCase().includes(search.toLowerCase())
    );
  });

  return (
    <>
      <Navbar />
      <div className="layout">
        <Sidebar
          problems={problems}
          setSelectedTopic={setSelectedTopic}
        />

        <div className="main">
          <FilterBar
            setDifficulty={setDifficulty}
            setSearch={setSearch}
          />

          <ProgressBar problems={problems} />

          {filtered.map((p) => (
            <ProblemCard
              key={p.id}
              problem={p}
              toggleSolved={toggleSolved}
            />
          ))}
        </div>
      </div>
    </>
  );
}

export default Sheet;
